-- 000_create_base_tables.sql
-- Creates and populates the three base tables: universities, hotels, hotel_accessible_universities.
-- On production Supabase these already exist — skip this file and start from 001.
-- On a fresh DB (local dev, staging): run this first, then 001 onward.

-- ============================================================
-- CREATE TABLES
-- ============================================================

CREATE TABLE IF NOT EXISTS universities (
    id                    uuid PRIMARY KEY,
    name                  text NOT NULL,
    address               text,
    city                  text,
    latitude              numeric,
    longitude             numeric,
    website_url           text,
    created_at            timestamptz DEFAULT now(),
    updated_at            timestamptz DEFAULT now(),
    maps_url              text,
    slug                  text,
    logo_url              text,
    university_short_name text,
    campus_url            text,
    university_type       text
);

CREATE TABLE IF NOT EXISTS hotels (
    id                        uuid PRIMARY KEY,
    name                      text NOT NULL,
    slug                      text,
    sub_header                text,
    description               text,
    address                   text,
    city                      text,
    latitude                  numeric,
    longitude                 numeric,
    map_embed_url             text,
    google_maps_link          text,
    representative_name       text,
    representative_photo_url  text,
    representative_email      text,
    representative_phone      text,
    representative_suggestion text,
    payment_details           text,
    instagram_group_link      text,
    video_url                 text,
    created_at                timestamptz DEFAULT now(),
    updated_at                timestamptz DEFAULT now(),
    district                  text,
    neighborhood              text,
    postal_code               text,
    nearby_landmarks          text[],
    nearby_transport_stations text[],
    local_keywords            text[],
    parking_info              text,
    public_transport_info     text,
    is_visible                boolean DEFAULT true,
    description_en            text,
    sub_header_en             text,
    property_type             text
);

CREATE TABLE IF NOT EXISTS hotel_accessible_universities (
    hotel_id                              uuid REFERENCES hotels(id),
    university_id                         uuid REFERENCES universities(id),
    commute_time_car_minutes              int4,
    commute_time_public_transport_minutes int4,
    commute_time_walk_minutes             int4,
    route_image_url                       text,
    route_link_url                        text,
    created_at                            timestamptz DEFAULT now(),
    PRIMARY KEY (hotel_id, university_id)
);

-- ============================================================
-- INSERT DATA
-- Universities first (no FK deps), then hotels, then junction.
-- ============================================================

